import { Component } from '@angular/core';
import { TextStatsService } from '../../services/text-stats.service';
import { Observable } from 'rxjs';

@Component({
  selector: 'app-navbar',
  templateUrl: './navbar.component.html',
  styleUrls: ['./navbar.component.css']
})
export class NavbarComponent {

  // Subscribe to live stats from the service
  wordCount$: Observable<number>;
  charCount$: Observable<number>;

  constructor(private statsService: TextStatsService) {
    this.wordCount$ = this.statsService.wordCount$;
    this.charCount$ = this.statsService.charCount$;
  }
}
<!-- Top navigation bar -->
<nav class="navbar">
  <div class="navbar-brand">
    <span class="brand-icon">‚ú¶</span>
    <span class="brand-name">TextFormatter</span>
  </div>

  <!-- Live stats badges driven by BehaviorSubject Observables -->
  <div class="navbar-stats">
    <div class="stat-badge">
      <span class="stat-label">words</span>
      <span class="stat-value">{{ wordCount$ | async }}</span>
    </div>
    <div class="stat-badge">
      <span class="stat-label">chars</span>
      <span class="stat-value">{{ charCount$ | async }}</span>
    </div>
  </div>
</nav>
